const d = $input.first().json;
const nome         = d['Nome do Cliente'] || '';
const tipo_cliente = d['Tipo de Cliente'] || '';
const uf           = d['UF'] || '';
const pedido       = d['Pedido'] || '';
const tipo_preco   = tipo_cliente.includes('Física') ? 'PF' : 'PMC';
const icms = {'SP':'18%','MG':'18%','ES':'18%','PR':'12%','SC':'17%','RS':'17%','MS':'17%','MT':'17%','CE':'17,5%','MA':'17,5%','PA':'17,5%','PI':'17,5%','RN':'17,5%','RJ':'20%','BA':'20%','DF':'20%','GO':'20%','PB':'20%','PE':'20%','SE':'20%','TO':'20%','AL':'20%','AM':'18%','AP':'18%','AC':'17%','RR':'17%','RO':'17,5%'};
const icms_aliq = icms[uf] || '17%';
const icms_regra = `ICMS ${icms_aliq} ${tipo_preco} — ${uf}`;
const query_busca = `${pedido} ${tipo_preco} UF ${uf} ICMS ${icms_aliq}`;

const system_prompt = `Você é um assistente especializado em orçamento de medicamentos da ACHÉ Laboratórios Farmacêuticos.

Ao receber uma solicitação de orçamento, siga obrigatoriamente estas etapas:

ETAPA 1 — EXTRAÇÃO DE ENTIDADES: Identifique produtos (por nome, código SAP ou princípio ativo), quantidades, tipo de cliente (${tipo_preco}) e UF (${uf}).

ETAPA 2 — IDENTIFICAÇÃO NO CATÁLOGO: Para cada produto, localize o bloco correspondente nos chunks pelo campo apresentacao, codigo_sap ou principio_ativo.

ETAPA 3 — SELEÇÃO DO PREÇO: Use a seção [5] PRECOS do chunk. Selecione a linha com alíquota ${icms_aliq} para ${tipo_preco}.

ETAPA 4 — CÁLCULO: preco_total = preco_unitario × quantidade. total = soma de todos.

ETAPA 5 — RETORNE APENAS JSON VÁLIDO SEM TEXTO ANTES OU DEPOIS:
{
  "itens": [{
    "produto": "nome completo",
    "codigo_sap": "código SAP",
    "chunk_id": "CHK-XXXXXXX",
    "principio_ativo": "substância",
    "quantidade": 0,
    "preco_unitario": 0.00,
    "preco_total": 0.00,
    "icms_aplicado": "${icms_aliq}",
    "tipo_preco": "${tipo_preco}",
    "observacao": ""
  }],
  "cliente": { "nome": "${nome}", "tipo": "${tipo_cliente}", "uf": "${uf}", "icms_regra": "${icms_regra}" },
  "total": 0.00,
  "alertas": []
}

REGRAS OBRIGATÓRIAS:

  - Nunca invente preços. Use SOMENTE os valores da seção [5] do catálogo.

  - Nunca omita campos do JSON, mesmo que o valor seja zero ou vazio.

  - Se um produto aparecer duplicado no catálogo (mesma apresentação, empresas

    diferentes), escolha a versão ACHÉ e informe em observacao.

  - Se a quantidade não for informada, assuma 1 e sinalize em alertas.

  - O JSON deve ser válido — sem comentários, sem trailing commas.

  - Adicione um campo de alerta para sinalizar se existe mais de um mesmo produto, só que de empresas diferentes`

return [{ json: { nome, tipo_cliente, uf, tipo_preco, icms_aliq, icms_regra, pedido, query_busca, system_prompt } }];

const item = $input.first();
let csv = '';
if (typeof item.json.data === 'string') csv = item.json.data;
else for (const k of Object.keys(item.json)) { if (typeof item.json[k] === 'string' && item.json[k].length > 100) { csv = item.json[k]; break; } }
csv = csv.replace(/^\uFEFF/, '');

const FORMA = {'COM':'comprimido','COM REV':'comprimido revestido','COM MAST':'comprimido mastigável','CAP':'cápsula','FR':'frasco','BG':'bisnaga','XPE':'xarope','AER':'aerossol','SOL':'solução','CREM':'creme','INJ':'injetável','FA':'frasco-ampola','AMP':'ampola','POM':'pomada','GTS':'gotas','GT':'gotas','DRG':'drágea','ENV':'envelope','SUSOR':'suspensão oral','LOC':'loção','SPR':'spray','GEL':'gel'};
const TARJA = {'TV':'tarja vermelha','VP':'tarja preta','VL':'sem tarja (venda livre)','TP':'tarja preta'};
const LISTA = {'POS':'lista positiva RENAME','NEG':'lista negativa'};
const REGIME = {'MONITORADO':'regime monitorado','LIBERADO':'regime liberado'};
const UF_ICMS = [
  {col:'ICMS 0 % (PF)',aliq:'0%',tc:'Pessoa Física',ufs:'isento'},
  {col:'ICMS 0 % (PMC)',aliq:'0%',tc:'PMC/Farmácia',ufs:'isento'},
  {col:'ICMS 12 %  (PF)',aliq:'12%',tc:'Pessoa Física',ufs:'SP, MG, PR, SC, RS'},
  {col:'ICMS 12 % (PMC) ',aliq:'12%',tc:'PMC/Farmácia',ufs:'SP, MG, PR, SC, RS'},
  {col:'ICMS 17 % (PF)',aliq:'17%',tc:'Pessoa Física',ufs:'SC, RS, MS, MT'},
  {col:'ICMS 17 % (PMC)',aliq:'17%',tc:'PMC/Farmácia',ufs:'SC, RS, MS, MT'},
  {col:'ICMS 17,5 % (PF)',aliq:'17,5%',tc:'Pessoa Física',ufs:'CE, MA, PA, PI, RN'},
  {col:'ICMS 17,5 % (PMC)',aliq:'17,5%',tc:'PMC/Farmácia',ufs:'CE, MA, PA, PI, RN'},
  {col:'ICMS 18 %  (PF)',aliq:'18%',tc:'Pessoa Física',ufs:'SP, MG, ES'},
  {col:'ICMS 18 %  (PMC)',aliq:'18%',tc:'PMC/Farmácia',ufs:'SP, MG, ES'},
  {col:'ICMS 20 % (PF)',aliq:'20%',tc:'Pessoa Física',ufs:'BA, DF, GO, PB, PE, RJ, SE, TO, AL'},
  {col:'ICMS 20 % (PMC)',aliq:'20%',tc:'PMC/Farmácia',ufs:'BA, DF, GO, PB, PE, RJ, SE, TO, AL'},
  {col:'ICMS 17 % (ALC) AC/RR (PF)',aliq:'17%',tc:'Pessoa Física',ufs:'AC, RR (ALC)'},
  {col:'ICMS 17 % (ALC) AC/RR (PMC)',aliq:'17%',tc:'PMC/Farmácia',ufs:'AC, RR (ALC)'},
  {col:'ICMS 17,5 % (ALC) RO (PF)',aliq:'17,5%',tc:'Pessoa Física',ufs:'RO (ALC)'},
  {col:'ICMS 17,5 % (ALC) RO (PMC)',aliq:'17,5%',tc:'PMC/Farmácia',ufs:'RO (ALC)'},
  {col:'ICMS 18 % (ALC) AM/AP (PF)',aliq:'18%',tc:'Pessoa Física',ufs:'AM, AP (ALC)'},
  {col:'ICMS 18 % (ALC) AM/AP (PMC)',aliq:'18%',tc:'PMC/Farmácia',ufs:'AM, AP (ALC)'}
];

function parseCSV(t) {
  const linhas = t.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
  const cab = linhas[0].split(';').map(c=>c.trim().replace(/^\uFEFF/,''));
  return linhas.slice(1).filter(l=>l.trim()).map(l=>{ const v=l.split(';'); const o={}; cab.forEach((c,i)=>{o[c]=(v[i]||'').trim();}); return o; });
}
function limpar(v) { const n=parseFloat((v||'').toString().trim().replace(',','.')); return isNaN(n)?'—':`R$ ${n.toFixed(2)}`; }

const rows = parseCSV(csv);
const chunks = [];
for (const row of rows) {
  const codigo = (row['CÓDIGO SAP']||'').trim(); if (!codigo) continue;
  const familia=(row['FAMÍLIA']||'').trim(), apresent=(row['APRESENTAÇÃO']||'').trim(), qtde=(row['QTDE']||'').trim(), um=(row['UM']||'').trim();
  const principio=(row['PRINCIPIO ATIVO']||'').trim(), un_neg=(row['UNIDADE DE NEGÓCIO']||'').trim(), empresa=(row['EMPRESA']||'').trim(), tipo=(row['TIPO DE MEDICAMENTO']||'').trim();
  const tarja_raw=(row['TARJA']||'').trim(), lista_raw=(row['LISTA']||'').trim(), regime=(row['REGIME DE PREÇOS']||'').trim();
  const ean=(row['CÓDIGO EAN']||'').trim(), reg_ms=(row['REGISTRO MS']||'').trim(), ggrem=(row['GGREM']||'').trim(), ncm=(row['NCM (CLASS FISCAL)']||'').trim(), ipi=(row['IPI']||'').trim(), pis=(row['% Pis']||'').trim(), cofins=(row['% Cofins']||'').trim();
  const forma=FORMA[um]||um, tarja=TARJA[tarja_raw]||tarja_raw, lista=LISTA[lista_raw]||lista_raw, regime_ext=REGIME[regime]||regime;
  const texto = `O produto ${apresent}, código SAP ${codigo}, é um medicamento ${tipo.toLowerCase()} fabricado pela ${empresa}. Princípio ativo: ${principio.toLowerCase()}, na forma de ${forma} com ${qtde} unidades. Segmento: ${un_neg.toLowerCase()}, ${tarja}, ${lista}, ${regime_ext}.`;
  const precos = UF_ICMS.map(({col,aliq,tc,ufs})=>`ICMS ${aliq} | ${tc} | ${ufs} | ${limpar(row[col])}`).join(' || ');
  const bloco = `--- CHK-${codigo} ---\n[1] codigo_sap: ${codigo} | ean: ${ean} | familia: ${familia} | apresentacao: ${apresent}\n[2] principio_ativo: ${principio} | forma: ${forma} | unidade: ${um} | qtde: ${qtde}\n[3] tipo: ${tipo} | tarja: ${tarja_raw} | lista: ${lista_raw} | regime: ${regime} | empresa: ${empresa} | segmento: ${un_neg}\n[4] ncm: ${ncm} | ipi: ${ipi}% | pis: ${pis}% | cofins: ${cofins}%\n[5] PRECOS: ${precos}\n[6] TEXTO: ${texto}`;
  chunks.push({ json: { pageContent: `${texto} | Família: ${familia} | Apresentação: ${apresent} | Princípio ativo: ${principio} | Código SAP: ${codigo} | Tipo: ${tipo} | Empresa: ${empresa}`, metadata: { chunk_id:`CHK-${codigo}`, codigo_sap:codigo, familia, apresentacao:apresent, principio_ativo:principio, tipo, empresa, tarja:tarja_raw, regime, un_neg, bloco_completo:bloco, precos_raw:precos } } });
}
console.log(`Chunks: ${chunks.length}`);
return chunks;

const input = $input.first().json;

// Garante que conteudo seja sempre string
let conteudo = input.response || input.text || input.output || '';
conteudo = typeof conteudo === 'string' ? conteudo : JSON.stringify(conteudo);

// Limpa e extrai o JSON
const limpo = conteudo
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .replace(/\\n/g, ' ')
  .replace(/\n/g, ' ')
  .trim();

let orcamento = {};
try {
  orcamento = JSON.parse(limpo);
} catch(e) {
  const match = limpo.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      orcamento = JSON.parse(match[0]);
    } catch(e2) {
      orcamento = { erro: 'JSON inválido', resposta_raw: conteudo };
    }
  } else {
    orcamento = { erro: 'JSON inválido', resposta_raw: conteudo };
  }
}

return [{ json: { orcamento } }];

let { orcamento } = $input.first().json;

// Se orcamento ainda for string, parseia agora
if (typeof orcamento === 'string' || orcamento.text) {
  const raw = typeof orcamento === 'string' ? orcamento : (orcamento.text || '');
  try {
    const limpo = raw.replace(/```json/gi,'').replace(/```/g,'').replace(/\\n/g,' ').trim();
    orcamento = JSON.parse(limpo);
  } catch(e) {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) {
      try { orcamento = JSON.parse(match[0]); }
      catch(e2) { orcamento = { erro: 'JSON inválido', resposta_raw: raw }; }
    } else {
      orcamento = { erro: 'JSON inválido', resposta_raw: raw };
    }
  }
}
if (orcamento.erro) return [{ json: { html: `<div style='padding:32px;font-family:Arial'><h2 style='color:#c0392b'>Erro ao processar</h2><p>${orcamento.erro}</p><pre style='background:#f9f9f9;padding:12px;border-radius:6px;font-size:12px;overflow-x:auto'>${String(orcamento.resposta_raw||'').replace(/</g,'&lt;')}</pre></div>` } }];

const itens=orcamento.itens||[], cliente=orcamento.cliente||{}, alertas=orcamento.alertas||[], total=Number(orcamento.total||0).toFixed(2);
const rows = itens.map((it,i)=>{ const c=i%2===0?'#F8FBFF':'#FFF'; const obs=it.observacao?`<br><small style='color:#e67e22'>${it.observacao}</small>`:''; return `<tr style='background:${c}'><td>${it.produto||''}${obs}</td><td style='text-align:center;font-family:monospace'>${it.codigo_sap||''}</td><td style='text-align:center'>${it.quantidade||''}</td><td style='text-align:right'>R$ ${Number(it.preco_unitario||0).toFixed(2)}</td><td style='text-align:right;font-weight:bold'>R$ ${Number(it.preco_total||0).toFixed(2)}</td><td style='text-align:center'><span style='background:#e8f0fe;color:#1E4D8C;padding:2px 8px;border-radius:10px;font-size:12px'>${it.icms_aplicado||''} ${it.tipo_preco||''}</span></td></tr>`; }).join('');
const alertasHtml=alertas.length?`<div style='background:#fff8e1;border-left:4px solid #f39c12;padding:12px 16px;margin-top:16px;border-radius:4px'><strong>⚠️ Alertas:</strong><ul style='margin:6px 0 0;padding-left:18px'>${alertas.map(a=>`<li>${a}</li>`).join('')}</ul></div>`:'';
const html=`<!DOCTYPE html><html lang='pt-BR'><head><meta charset='UTF-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Orçamento ACHÉ</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;background:#f0f4f8;padding:24px 16px}.card{background:#fff;border-radius:12px;padding:28px;max-width:1000px;margin:0 auto;box-shadow:0 4px 20px rgba(0,0,0,.08)}.header{display:flex;align-items:center;gap:12px;margin-bottom:24px;padding-bottom:16px;border-bottom:2px solid #e8f0fe}.header h1{color:#1E4D8C;font-size:20px}.badge{background:#e8f0fe;color:#1E4D8C;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:bold}.info{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;margin-bottom:20px}.box{background:#f8fbff;border:1px solid #e0eaff;border-radius:8px;padding:12px}.box label{font-size:11px;color:#888;display:block;margin-bottom:3px;text-transform:uppercase}.box span{font-weight:bold;color:#1E4D8C;font-size:14px}table{width:100%;border-collapse:collapse;font-size:13px}thead th{background:#1E4D8C;color:#fff;padding:10px 12px;text-align:left;font-size:11px;text-transform:uppercase}tbody td{padding:9px 12px;border-bottom:1px solid #f0f0f0}.total td{background:#e8f0fe;font-size:14px;padding:12px;border-top:2px solid #1E4D8C}.footer{margin-top:20px;text-align:center;color:#aaa;font-size:11px}</style></head><body><div class='card'><div class='header'><div style='flex:1'><h1>🧾 Orçamento ACHÉ Laboratórios</h1><p style='color:#666;font-size:12px;margin-top:3px'>Gerado via RAG + Chunking Semântico Híbrido + Qdrant</p></div><span class='badge'>RAG + QA Chain</span></div><div class='info'><div class='box'><label>Cliente</label><span>${cliente.nome||''}</span></div><div class='box'><label>Tipo</label><span>${cliente.tipo||''}</span></div><div class='box'><label>UF</label><span>${cliente.uf||''}</span></div><div class='box'><label>ICMS</label><span>${cliente.icms_regra||''}</span></div></div><table><thead><tr><th>Produto</th><th style='text-align:center'>Cód. SAP</th><th style='text-align:center'>Qtd</th><th style='text-align:right'>Preço Unit.</th><th style='text-align:right'>Total</th><th style='text-align:center'>ICMS</th></tr></thead><tbody>${rows}<tr class='total'><td colspan='4'><strong>TOTAL GERAL</strong></td><td style='text-align:right'><strong>R$ ${total}</strong></td><td></td></tr></tbody></table>${alertasHtml}<div class='footer'>Extração e Preparação de Dados — Chunking Semântico Híbrido — ACHÉ · 2025</div></div></body></html>`;
return [{ json: { html } }];
